async function main() {
  const { channelId } = await getTargetChannel();

  const now = new Date();
  const toIso = now.toISOString();
  const fromIso = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();

  const result = await summarizeChannel({ channelId, fromIso, toIso });

  return result;
}

return await main();

